import React from 'react';

export const ShelterCard = ({ shelter, onClick, isSelected, distance }) => {
  const occupancyRate = (shelter.currentOccupancy / shelter.capacity) * 100;
  const isNearFull = shelter.status === 'NEAR_FULL' || occupancyRate >= 90;
  
  return (
    <div 
      className={`shelter-card ${onClick ? 'card-clickable' : ''} ${isSelected ? 'selected' : ''} ${isNearFull ? 'near-full' : ''}`} 
      onClick={onClick}
    >
      <div className="shelter-card-content">
        <div className="card-header">
          <span className="card-title">{shelter.name}</span>
          <span className={`badge ${shelter.status}`}>{shelter.status}</span>
        </div>
        
        <div className="shelter-info-row">
          <svg className="info-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path>
            <circle cx="12" cy="10" r="3"></circle>
          </svg>
          <span className="info-text">{shelter.address}</span>
        </div>
        
        <div className="shelter-info-row">
          <div className="shelter-info-left">
            <svg className="info-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"></path>
              <circle cx="9" cy="7" r="4"></circle>
              <path d="M23 21v-2a4 4 0 0 0-3-3.87"></path>
              <path d="M16 3.13a4 4 0 0 1 0 7.75"></path>
            </svg>
            <span className="info-text">Sức chứa: {shelter.currentOccupancy}/{shelter.capacity}</span>
          </div>
          {distance != null && (
            <div className="shelter-distance">
              {distance.toFixed(1)} km
            </div>
          )}
        </div>
      </div>
      
      <div className="shelter-progress-container">
        <div 
          className="shelter-progress-bar" 
          style={{ width: `${Math.min(occupancyRate, 100)}%` }}
        ></div>
      </div>
    </div>
  );
};

export const AlertCard = ({ alert }) => (
  <div className="card" style={{borderLeft: `4px solid ${alert.severityLevel === 'CRITICAL' ? 'red' : 'orange'}`}}>
    <div className="card-header">
      <span className="card-title">{alert.title}</span>
      <span className={`badge ${alert.severityLevel}`}>{alert.severityLevel}</span>
    </div>
    <p>{alert.description}</p>
    <small>Khu vực: {alert.affectedArea}</small>
  </div>
);

export const NotificationItem = ({ notif, onRead }) => (
  <div className="card" style={{opacity: notif.isRead ? 0.6 : 1}}>
    <strong>{notif.title}</strong>
    <p>{notif.message}</p>
    {!notif.isRead && <button className="btn" onClick={() => onRead(notif.id)} style={{marginTop:'10px', padding:'5px 10px'}}>Đã đọc</button>}
  </div>
);
